module RefModule (
	input clk,
	input set,
	input reset,
	input [7:0] data_in,
	output reg [7:0] q);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
	if (reset)
		q <= 8'b00000000;
	else if (set)
		q <= 8'b11111111;
	else
		q <= data_in;
end

endmodule
